create table roma_main.ftth_preorders_fuzzydouble (
    id           number
        generated by default on null as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 start with 1 nocache
        noorder nocycle nokeep noscale
    not null enable,
    request_id   number,
    ftth_id      varchar2(100 byte) not null enable,
    fuzzy_rowid  varchar2(100 byte),
    score_datum  date not null enable,
    score_typ    varchar2(3 byte) not null enable,
    score        number,
    status       varchar2(3 byte),
    errorcode    number,
    errortext    varchar2(1000 byte),
    kundennummer varchar2(100 byte)
);

create unique index roma_main.ftth_preorders_fuzzydouble_pk on
    roma_main.ftth_preorders_fuzzydouble (
        id
    );

alter table roma_main.ftth_preorders_fuzzydouble
    add constraint ftth_preorders_fuzzydouble_pk
        primary key ( id )
            using index roma_main.ftth_preorders_fuzzydouble_pk enable;


